export function renderBookingStep3() {
    const bd = state.bookingData;
    const calYear = state._calYear || new Date().getFullYear();
    const calMonth = state._calMonth || new Date().getMonth();
    const days = getDaysOfMonth(calYear, calMonth);
    const today = new Date();
    const isCurrentMonth = today.getMonth() === calMonth && today.getFullYear() === calYear;

    return `
<div class="space-y-4 animate-fade-in">
    <h3 class="font-bold text-system-text text-lg">Выберите дату</h3>
    <div class="bg-system-main rounded-[32px] p-6 border border-system-border">
        <div class="flex items-center justify-between mb-6">
            <button onclick="changeMonth(-1)" class="w-10 h-10 flex items-center justify-center hover:bg-system-surface rounded-xl transition-all font-bold text-system-muted opacity-70">❮</button>
            <div class="flex flex-col items-center gap-1">
                <span class="font-black text-system-text tracking-tight">${getMonthName(calMonth)} ${calYear}</span>
                <span onclick="state._calMonth=new Date().getMonth(); state._calYear=new Date().getFullYear(); window.render();" class="text-xs font-bold text-primary-500 cursor-pointer hover:underline">Сегодня</span>
            </div>
            <button onclick="changeMonth(1)" class="w-10 h-10 flex items-center justify-center hover:bg-system-surface rounded-xl transition-all font-bold text-system-muted opacity-70">❯</button>
        </div>
        <div class="grid grid-cols-7 gap-2 text-center mb-4 text-[11px] font-black text-system-muted opacity-70 uppercase tracking-widest">
            <div>Пн</div><div>Вт</div><div>Ср</div><div>Чт</div><div>Пт</div><div>Сб</div><div>Вс</div>
        </div>
        <div class="grid grid-cols-7 gap-2">
            ${days.map(d => {
                if (!d) return '<div></div>';
                const dayDate = new Date(calYear, calMonth, d);
                const todayDate = new Date();
                const isPast = dayDate < new Date().setHours(0,0,0,0);
                const isSelected = bd.date && bd.date.getDate() === d && bd.date.getMonth() === calMonth && bd.date.getFullYear() === calYear;
                const isToday = d === todayDate.getDate() && calMonth === todayDate.getMonth() && calYear === todayDate.getFullYear();
                return `
                    <div onclick="${isPast ? '' : `selectDate(${calYear}, ${calMonth}, ${d}); goToBookingStep(4)`}" 
                         class="aspect-square flex items-center justify-center rounded-2xl text-sm font-bold cursor-pointer transition-all duration-200
                         ${isPast ? 'text-system-muted opacity-40 cursor-not-allowed' : isSelected ? 'bg-primary-500 text-system-surface shadow-lg shadow-primary-200 scale-110' : isToday ? 'bg-primary-50 text-primary-500 border-2 border-primary-400' : 'bg-system-surface hover:bg-primary-50 text-system-text shadow-sm border border-system-border'}">
                        ${d}
                    </div>`;
            }).join('')}
        </div>
    </div>
    <div class="grid grid-cols-2 gap-2 mt-2">
        <button onclick="goToBookingStep(2)" class="w-full py-4 rounded-2xl border-2 border-system-border font-bold text-system-muted opacity-70 hover:bg-system-main transition-colors">← Назад</button>
        <button onclick="nextStepDefault()" class="w-full py-4 rounded-2xl bg-primary-50 text-primary-500 font-bold hover:bg-primary-50 transition-colors">Далее →</button>
    </div>
</div>`;
}

