export function renderBookingStep4() {
    const bd = state.bookingData;
    const slots = (window.timeSlots || []);

    const isSlotTaken = (t) => {
        if (!bd.date) return false;
        
        const d = bd.date.getDate();
        const m = bd.date.getMonth();
        const yy = bd.date.getFullYear();
        const dd = String(d).padStart(2, '0');
        const mm = String(m + 1).padStart(2, '0');
        
        const dateStrDB = `${dd}.${mm}.${yy}`;
        
        // formatDate fallback
        const monthsNames = ['января', 'февраля', 'марта', 'апреля', 'мая', 'июня', 'июля', 'августа', 'сентября', 'октября', 'ноября', 'декабря'];
        const reqDate = d + ' ' + monthsNames[m];

        const todaysBookings = state.bookings.filter(b => 
            b.status !== 'cancelled' && (b.date === dateStrDB || b.date === reqDate) && b.time === t
        );

        if (bd.type === 'master') {
            return todaysBookings.some(b => b.masterId === bd.targetId);
        } else {
            if (bd.masterId) {
                return todaysBookings.some(b => b.masterId === bd.masterId);
            } else {
                const salonMasters = masters.filter(mas => mas.salonId === bd.targetId);
                if (salonMasters.length === 0) return false;
                const busyMasters = todaysBookings.filter(b => salonMasters.some(sm => sm.id === b.masterId));
                return busyMasters.length >= salonMasters.length;
            }
        }
    };

    return `
<div class="space-y-4 animate-fade-in">
    <h3 class="font-bold text-system-text text-lg">Выберите время</h3>
    <p class="text-sm font-medium text-primary-500 bg-primary-50 py-2 px-4 rounded-xl inline-block"><svg class="w-5 h-5 inline-block" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24"><rect width="18" height="18" x="3" y="4" rx="2" ry="2"/><line stroke-linecap="round" stroke-linejoin="round" x1="16" x2="16" y1="2" y2="6"/><line stroke-linecap="round" stroke-linejoin="round" x1="8" x2="8" y1="2" y2="6"/><line stroke-linecap="round" stroke-linejoin="round" x1="3" x2="21" y1="10" y2="10"/></svg> ${bd.date ? formatDate(bd.date) : ''}</p>
    <div class="grid grid-cols-4 gap-3">
        ${slots.length > 0 ? slots.map(t => {
            const unavailable = isSlotTaken(t);
            if (unavailable) {
                return `
                <div class="py-4 rounded-2xl border-2 border-system-border text-center text-sm font-black cursor-not-allowed bg-system-main text-system-muted opacity-40">
                    ${t}
                </div>`;
            }
            return `
            <div onclick="state.bookingData.time = '${t}'; goToBookingStep(5)" 
                 class="py-4 rounded-2xl border-2 text-center text-sm font-black cursor-pointer transition-all duration-200
                 ${bd.time === t ? 'border-primary-500 bg-primary-50 text-primary-500 shadow-inner' : 'bg-system-surface border-system-border hover:border-primary-400 text-system-muted shadow-sm'}">
                ${t}
            </div>`;
        }).join('') : '<p class="col-span-4 text-center text-system-muted opacity-70 py-4 font-bold">Слоты времени не найдены</p>'}
    </div>
    <div class="grid grid-cols-2 gap-2 mt-2">
        <button onclick="goToBookingStep(3)" class="w-full py-4 rounded-2xl border-2 border-system-border font-bold text-system-muted opacity-70 hover:bg-system-main transition-colors">← Назад</button>
        <button onclick="nextStepDefault()" class="w-full py-4 rounded-2xl bg-primary-50 text-primary-500 font-bold hover:bg-primary-50 transition-colors">Далее →</button>
    </div>
</div>`;
}

