    // Определяем целевой объект в зависимости от типа (салон или мастер)
    const target = bd.type === 'salon' 
        ? salons.find(s => s.id === bd.targetId) 
        : masters.find(m => m.id === bd.targetId);

    // Определяем мастера
    const master = bd.type === 'master' 
        ? target 
        : (bd.masterId ? masters.find(m => m.id === bd.masterId) : null);

    // Определяем название локации и итоговую цену
    let placeName = '';
    let price = 0;

